import {
  forwardRef,
  useRef,
  useImperativeHandle,
  type HTMLAttributes,
} from "react";
import { useCheckboxGroupItem, useFocusRing, mergeProps } from "react-aria";
import { useCheckboxGroupContext } from "../CheckboxGroup";
import * as styles from "./CheckboxItem.css";
import type { CheckboxItemSize } from "./CheckboxItem.config";
import { DEFAULT_CHECKBOX_ITEM_SIZE } from "./CheckboxItem.config";
import { clsx } from "clsx";
import CheckIcon from "@fortawesome/fontawesome-pro/svgs/solid/check.svg";

interface CheckboxItemCustomProps {
  /**
   * The visual size of the checkbox
   * @default 'md'
   */
  size?: CheckboxItemSize;

  /**
   * The value of the checkbox (required for CheckboxGroup).
   */
  value: string;

  /**
   * Whether the checkbox is disabled
   */
  disabled?: boolean;

  /**
   * The id for the checkbox input (also used for label htmlFor)
   */
  id?: string;

  /**
   * The name for the checkbox input (for form submission)
   */
  name?: string;

  /**
   * Accessible label for the checkbox
   */
  "aria-label"?: string;

  /**
   * ID of the element that labels the checkbox
   */
  "aria-labelledby"?: string;

  /**
   * ID of the element that describes the checkbox
   */
  "aria-describedby"?: string;

  /**
   * Whether to hide the focus ring (for use inside tile components where
   * the parent handles focus styling)
   * @default false
   */
  hideFocusRing?: boolean;
}

export interface CheckboxItemProps
  extends
    Omit<HTMLAttributes<HTMLSpanElement>, keyof CheckboxItemCustomProps>,
    CheckboxItemCustomProps {}

/**
 * The core checkbox visual component.
 *
 * Must be used inside a CheckboxGroup, which manages the selection state.
 * The checkbox automatically participates in the group's value management.
 *
 * @example
 * <CheckboxGroup value={selectedValues} onChange={setSelectedValues}>
 *   <CheckboxItem value="option1" aria-label="Option 1" />
 *   <CheckboxItem value="option2" aria-label="Option 2" />
 * </CheckboxGroup>
 */
export const CheckboxItem = forwardRef<HTMLInputElement, CheckboxItemProps>(
  (
    {
      size = DEFAULT_CHECKBOX_ITEM_SIZE,
      disabled = false,
      value,
      className,
      id,
      name,
      "aria-label": ariaLabel,
      "aria-labelledby": ariaLabelledBy,
      "aria-describedby": ariaDescribedBy,
      hideFocusRing = false,
      ...restProps
    },
    forwardedRef
  ) => {
    const inputRef = useRef<HTMLInputElement>(null);

    // Forward the ref to the input element
    useImperativeHandle(
      forwardedRef,
      () => inputRef.current as HTMLInputElement
    );

    // Get checkbox group state from context (provided by CheckboxGroup)
    const groupState = useCheckboxGroupContext();

    // Get checkbox behavior and accessibility props
    const { inputProps, isSelected, isDisabled } = useCheckboxGroupItem(
      {
        value,
        isDisabled: disabled,
        ...(ariaLabel !== undefined && { "aria-label": ariaLabel }),
        ...(ariaLabelledBy !== undefined && {
          "aria-labelledby": ariaLabelledBy,
        }),
        ...(ariaDescribedBy !== undefined && {
          "aria-describedby": ariaDescribedBy,
        }),
        ...(id !== undefined && { id }),
        ...(name !== undefined && { name }),
      },
      groupState,
      inputRef
    );

    // Get focus ring state for keyboard focus visibility
    const { isFocusVisible, focusProps } = useFocusRing();

    // Check if invalid from group state
    const isInvalid = groupState.isInvalid;

    const checkboxClasses = clsx(
      styles.checkboxItem({
        size,
      }),
      className
    );

    const iconClassName = styles.checkIcon({
      size,
    });

    return (
      <span
        className={checkboxClasses}
        data-checked={isSelected || undefined}
        data-disabled={isDisabled || undefined}
        data-invalid={isInvalid || undefined}
        data-focus-visible={(!hideFocusRing && isFocusVisible) || undefined}
        {...restProps}
      >
        <input
          {...mergeProps(inputProps, focusProps)}
          ref={inputRef}
          className={styles.hiddenInput}
        />
        {isSelected && (
          <CheckIcon className={iconClassName} aria-hidden="true" />
        )}
      </span>
    );
  }
);

CheckboxItem.displayName = "CheckboxItem";
